python3 -c "
import csv
questions = []
with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        if row['is_resolved'] == 'False':
            pred = row.get('my_prediction', '')
            if not pred or pred == '' or pred == 'None':
                questions.append(row)

from datetime import datetime
def get_date(q):
    try:
        return datetime.strptime(q['resolution_date'], '%Y-%m-%d')
    except:
        return datetime(2030, 1, 1)

questions.sort(key=get_date)

print(f'Total unanswered: {len(questions)}')
for q in questions[:30]:
    print(f\"qid: {q['qid']}, date: {q['resolution_date']}, title: {q['title'][:80]}\")
"

